-- ==========================================================
-- TRL Debuts Import Script
-- Generated from: The TRL Archive - Debuts.htm
-- Target DB: C:/Music Stats DB/music-stats.db
-- ==========================================================

CREATE TABLE IF NOT EXISTS trl_debut (
    id                INTEGER PRIMARY KEY AUTOINCREMENT,
    days_on_countdown INTEGER NOT NULL,
    debut_date        TEXT,            -- YYYY-MM-DD
    debut_position    INTEGER NOT NULL,
    song_title        TEXT NOT NULL,
    artist_name       TEXT NOT NULL,
    song_id           INTEGER,         -- FK to Song.id (nullable, matched after import)
    FOREIGN KEY (song_id) REFERENCES Song(id)
);

CREATE INDEX IF NOT EXISTS idx_trl_debut_song_id    ON trl_debut(song_id);
CREATE INDEX IF NOT EXISTS idx_trl_debut_debut_date ON trl_debut(debut_date);

-- Insert TRL debut entries
BEGIN TRANSACTION;

COMMIT;

-- ==========================================================
-- Auto-match TRL entries to songs already in your library.
-- Matching: case-insensitive song title + artist name prefix
-- (handles "Artist f/..." style credits).
-- ==========================================================

BEGIN TRANSACTION;

UPDATE trl_debut
SET song_id = (
    SELECT s.id
    FROM   Song s
    JOIN   Artist a ON a.id = s.artist_id
    WHERE  LOWER(TRIM(s.name)) = LOWER(TRIM(trl_debut.song_title))
      AND (
          LOWER(TRIM(a.name)) = LOWER(TRIM(trl_debut.artist_name))
          OR LOWER(TRIM(trl_debut.artist_name)) LIKE LOWER(TRIM(a.name)) || ' %'
          OR LOWER(TRIM(trl_debut.artist_name)) LIKE LOWER(TRIM(a.name)) || ' f/%'
      )
    ORDER BY s.id
    LIMIT 1
)
WHERE song_id IS NULL;

COMMIT;

-- Match summary
SELECT 'Total entries'     AS label, COUNT(*) AS count FROM trl_debut
UNION ALL
SELECT 'Matched to song'   AS label, COUNT(*) AS count FROM trl_debut WHERE song_id IS NOT NULL
UNION ALL
SELECT 'Unmatched'         AS label, COUNT(*) AS count FROM trl_debut WHERE song_id IS NULL;
